import com.fsck.k9.Preferences
import org.junit.Before
import org.junit.Test
import org.mockito.kotlin.mock
import org.mockito.kotlin.whenever

class UnifiedInboxConfiguratorTest : K9RobolectricTest() {
    private lateinit var preferences: Preferences
    private lateinit var accountManager: AccountManager
    private lateinit var unifiedInboxConfigurator: UnifiedInboxConfigurator

    @Before
    fun setUp() {
        preferences = Preferences.getPreferences()
        accountManager = mock()
        unifiedInboxConfigurator = UnifiedInboxConfigurator(accountManager, preferences)

        // Reset the unified inbox setting
        K9.isShowUnifiedInbox = false
    }

    @Test
    fun `configureUnifiedInbox should not enable unified inbox when only one account exists`() {
        // Given: Only one account
        whenever(accountManager.getAccounts()).thenReturn(listOf(mock()))

        // When: Configure unified inbox
        unifiedInboxConfigurator.configureUnifiedInbox()

        // Then: Unified inbox should NOT be enabled
        assertThat(K9.isShowUnifiedInbox).isFalse()
    }

    @Test
    fun `configureUnifiedInbox should enable unified inbox when two accounts exist`() {
        // Given: Two accounts
        whenever(accountManager.getAccounts()).thenReturn(listOf(mock(), mock()))

        // When: Configure unified inbox
        unifiedInboxConfigurator.configureUnifiedInbox()

        // Then: Unified inbox should be enabled in memory
        assertThat(K9.isShowUnifiedInbox).isTrue()

        // And: Settings should be persisted immediately (verify by reloading)
        K9.loadPrefs(preferences.storage)
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox should enable unified inbox when multiple accounts exist`() {
        // Given: Multiple accounts
        whenever(accountManager.getAccounts()).thenReturn(listOf(mock(), mock(), mock()))

        // When: Configure unified inbox
        unifiedInboxConfigurator.configureUnifiedInbox()

        // Then: Unified inbox should be enabled in memory
        assertThat(K9.isShowUnifiedInbox).isTrue()

        // And: Settings should be persisted immediately (verify by reloading)
        K9.loadPrefs(preferences.storage)
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }

    @Test
    fun `configureUnifiedInbox should not affect existing unified inbox state when only one account`() {
        // Given: Only one account and unified inbox already enabled
        whenever(accountManager.getAccounts()).thenReturn(listOf(mock()))
        K9.isShowUnifiedInbox = true

        // When: Configure unified inbox
        unifiedInboxConfigurator.configureUnifiedInbox()

        // Then: Unified inbox should remain enabled
        assertThat(K9.isShowUnifiedInbox).isTrue()
    }
}
